import type { NextApiRequest, NextApiResponse } from "next";
import { Pool } from "pg";

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: { rejectUnauthorized: false }, // necessário no Neon
});

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  try {
    const client = await pool.connect();

    const query = `
      SELECT 
        c.id,
        c.logo,
        c.title,
        c.description,
        c.website,
        c.mail,
        c.social,
        c.color,
        COALESCE(array_agg(cc.category) FILTER (WHERE cc.category IS NOT NULL), '{}') AS categories
      FROM communities c
      LEFT JOIN community_categories cc ON c.id = cc.community_id
      GROUP BY c.id
      ORDER BY c.id;
    `;

    const { rows } = await client.query(query);
    client.release();

    // Garantir que categories é array e social é objeto
    const cleanedRows = rows.map((row) => ({
      ...row,
      categories: Array.isArray(row.categories) ? row.categories : [],
      social: row.social ? JSON.parse(row.social) : {},
    }));

    res.status(200).json(cleanedRows);
  } catch (error: any) {
    console.error("Erro na API:", error.message);
    res.status(500).json({ error: "Erro ao buscar comunidades", details: error.message });
  }
}
